    vle64.v v21, (x4)                             # Load desired value from memory into v21
    la x19, vector_ls_random_base                 # Load address pointer integer register for loads
    csrr x1, vtype                                # save vtype register for after load
    csrr x9, vl                                   # save vl register for after load
    vsetvli x0, x9, e8, m1, tu, mu                # set lmul to 1 for load
    la x22, custom_idx_trunc_sew64                # Load address of desired value
    vle8.v v31, (x22)                             # Load desired value from memory into v31
    vsetvl x0, x9, x1                             # restore vl and vtype setting
    csrr x31, vtype                               # save vtype register for after load
    csrr x24, vl                                  # save vl register for after load
    vsetvl x10, x0, x31                           # set vl to vlmax
    add x10, x10, x10                             # save vlmax * 2
    vsetvli x0, x24, e8, m1, ta, ma               # setting sew to vs2 eew
